from itertools import combinations
class Solution:
    def countPairs(self, nums, k):
        n = len(nums)
        cnt = 0
        for i, j in combinations(range(n), 2):
            if nums[i] == nums[j] and (i * j) % k == 0:
                cnt += 1
        return cnt

